class InMemoryDatabase:
    """Thread-safe in-memory database for users and tokens."""

    def __init__(self):
        self._users: Dict[str, dict] = {}
        self._tokens: Dict[str, str] = {}  # token -> user_id
        self._lock = threading.RLock()
        self._seed_data()

    def _seed_data(self):
        """Seed with initial test data."""
        seed_users = [
            {
                "user_id": "user-001",
                "username": "admin",
                "email": "admin@example.com",
                "password_hash": self._hash_password("admin123"),
                "full_name": "System Administrator",
                "created_at": datetime.utcnow().isoformat(),
                "is_active": True,
                "metadata": {"role": "admin", "department": "IT"}
            },
            {
                "user_id": "user-002",
                "username": "john_doe",
                "email": "john@example.com",
                "password_hash": self._hash_password("password123"),
                "full_name": "John Doe",
                "created_at": datetime.utcnow().isoformat(),
                "is_active": True,
                "metadata": {"role": "user", "department": "Engineering"}
            },
            {
                "user_id": "user-003",
                "username": "jane_smith",
                "email": "jane@example.com",
                "password_hash": self._hash_password("password456"),
                "full_name": "Jane Smith",
                "created_at": datetime.utcnow().isoformat(),
                "is_active": True,
                "metadata": {"role": "user", "department": "Marketing"}
            },
        ]
        for user in seed_users:
            self._users[user["user_id"]] = user

    @staticmethod
    def _hash_password(password: str) -> str:
        return hashlib.sha256(password.encode()).hexdigest()

    def authenticate(self, username: str, password: str) -> Optional[dict]:
        with self._lock:
            password_hash = self._hash_password(password)
            for user in self._users.values():
                if user["username"] == username and user["password_hash"] == password_hash:
                    if user["is_active"]:
                        return user
            return None

    def create_token(self, user_id: str) -> str:
        with self._lock:
            token = str(uuid.uuid4()) + "-" + str(uuid.uuid4())
            self._tokens[token] = user_id
            return token

    def validate_token(self, token: str) -> Optional[dict]:
        with self._lock:
            user_id = self._tokens.get(token)
            if user_id:
                return self._users.get(user_id)
            return None

    def invalidate_token(self, token: str) -> bool:
        with self._lock:
            if token in self._tokens:
                del self._tokens[token]
                return True
            return False

    def register_user(self, username: str, email: str, password: str, full_name: str) -> Optional[str]:
        with self._lock:
            # Check for duplicate username or email
            for user in self._users.values():
                if user["username"] == username:
                    return None
                if user["email"] == email:
                    return None

            user_id = f"user-{str(uuid.uuid4())[:8]}"
            self._users[user_id] = {
                "user_id": user_id,
                "username": username,
                "email": email,
                "password_hash": self._hash_password(password),
                "full_name": full_name,
                "created_at": datetime.utcnow().isoformat(),
                "is_active": True,
                "metadata": {"role": "user"}
            }
            return user_id

    def get_user(self, user_id: str) -> Optional[dict]:
        with self._lock:
            return self._users.get(user_id)

    def list_users(self, page: int = 1, page_size: int = 10, filter_str: str = "") -> tuple:
        with self._lock:
            all_users = list(self._users.values())

            if filter_str:
                filter_lower = filter_str.lower()
                all_users = [
                    u for u in all_users
                    if filter_lower in u["username"].lower()
                    or filter_lower in u["full_name"].lower()
                    or filter_lower in u["email"].lower()
                ]

            total_count = len(all_users)
            start = (page - 1) * page_size
            end = start + page_size
            return all_users[start:end], total_count

    def update_user(self, user_id: str, email: str = "", full_name: str = "",
                    metadata: Dict[str, str] = None) -> Optional[dict]:
        with self._lock:
            user = self._users.get(user_id)
            if not user:
                return None
            if email:
                user["email"] = email
            if full_name:
                user["full_name"] = full_name
            if metadata:
                user["metadata"].update(metadata)
            return user

    def delete_user(self, user_id: str) -> bool:
        with self._lock:
            if user_id in self._users:
                del self._users[user_id]
                # Remove associated tokens
                tokens_to_remove = [
                    t for t, uid in self._tokens.items() if uid == user_id
                ]
                for t in tokens_to_remove:
                    del self._tokens[t]
                return True
            return False


