        def Login(self, request, context):
            logger.info(f"Login attempt for user: {request.username}")

            if not request.username or not request.password:
                context.set_code(StatusCode.INVALID_ARGUMENT)
                context.set_details("Username and password are required")
                return LoginResponse(
                    success=False,
                    message="Username and password are required"
                )

            user = db.authenticate(request.username, request.password)
            if user:
                token = db.create_token(user["user_id"])
                logger.info(f"Login successful for user: {request.username}")
                return LoginResponse(
                    success=True,
                    token=token,
                    message="Login successful",
                    user=user_dict_to_data(user)
                )
            else:
                logger.warning(f"Login failed for user: {request.username}")
                context.set_code(StatusCode.UNAUTHENTICATED)
                context.set_details("Invalid credentials")
                return LoginResponse(
                    success=False,
                    message="Invalid username or password"
                )

        def Register(self, request, context):
            logger.info(f"Registration attempt for user: {request.username}")

            if not all([request.username, request.email, request.password]):
                context.set_code(StatusCode.INVALID_ARGUMENT)
                context.set_details("Username, email, and password are required")
                return RegisterResponse(
                    success=False,
                    message="Username, email, and password are required"
                )

            if len(request.password) < 6:
                context.set_code(StatusCode.INVALID_ARGUMENT)
                context.set_details("Password must be at least 6 characters")
                return RegisterResponse(
                    success=False,
                    message="Password must be at least 6 characters"
                )

            user_id = db.register_user(
                request.username, request.email,
                request.password, request.full_name
            )

            if user_id:
                logger.info(f"Registration successful: {request.username} -> {user_id}")
                return RegisterResponse(
                    success=True,
                    message="Registration successful",
                    user_id=user_id
                )
            else:
                logger.warning(f"Registration failed - duplicate: {request.username}")
                context.set_code(StatusCode.ALREADY_EXISTS)
                context.set_details("Username or email already exists")
                return RegisterResponse(
                    success=False,
                    message="Username or email already exists"
                )

        def ValidateToken(self, request, context):
            logger.info("Token validation request")

            if not request.token:
                context.set_code(StatusCode.INVALID_ARGUMENT)
                return ValidateTokenResponse(valid=False)

            user = db.validate_token(request.token)
            if user:
                return ValidateTokenResponse(
                    valid=True,
                    user_id=user["user_id"],
                    username=user["username"]
                )
            else:
                return ValidateTokenResponse(valid=False)

        def Logout(self, request, context):
            logger.info("Logout request")

            if not request.token:
                context.set_code(StatusCode.INVALID_ARGUMENT)
                return LogoutResponse(success=False, message="Token is required")

            success = db.invalidate_token(request.token)
            if success:
                return LogoutResponse(success=True, message="Logged out successfully")
            else:
                return LogoutResponse(success=False, message="Invalid token")

