def run_server():
    """Run the gRPC server."""
    if not GRPC_AVAILABLE:
        print("ERROR: grpcio is not installed.")
        print("Install with: pip install grpcio grpcio-tools")
        return

    server = MicroservicesServer(host="0.0.0.0", port=50051, max_workers=10)
    server.start()

    try:
        server.wait_for_termination()
    except KeyboardInterrupt:
        server.stop(grace=5.0)


def run_client_demo():
    """Run a client demo that exercises all service endpoints."""
    if not GRPC_AVAILABLE:
        print("ERROR: grpcio is not installed.")
        print("Install with: pip install grpcio grpcio-tools")
        return

    import json

    def pretty_print(label, data):
        print(f"\n{'=' * 50}")
        print(f"  {label}")
        print(f"{'=' * 50}")
        print(json.dumps(data, indent=2, default=str))

    with MicroservicesClient(host="localhost", port=50051) as client:
        # 1. Register a new user
        print("\n" + "#" * 60)
        print("  MICROSERVICES gRPC CLIENT DEMO")
        print("#" * 60)

        try:
            result = client.register(
                username="new_user",
                email="newuser@example.com",
                password="securepass123",
                full_name="New User"
            )
            pretty_print("1. REGISTER NEW USER", result)
        except grpc.RpcError as e:
            print(f"Register failed: {e}")

        # 2. Login
        try:
            result = client.login("admin", "admin123")
            pretty_print("2. LOGIN (admin)", result)
            token = result.get('token', '')
        except grpc.RpcError as e:
            print(f"Login failed: {e}")
            token = ''

        # 3. Validate token
        try:
            result = client.validate_token(token)
            pretty_print("3. VALIDATE TOKEN", result)
        except grpc.RpcError as e:
            print(f"Validate token failed: {e}")

        # 4. Get user
        try:
            result = client.get_user("user-001")
            pretty_print("4. GET USER (user-001)", result)
        except grpc.RpcError as e:
            print(f"Get user failed: {e}")

        # 5. List users
        try:
            result = client.list_users(page=1, page_size=10)
            pretty_print("5. LIST USERS", result)
        except grpc.RpcError as e:
            print(f"List users failed: {e}")

        # 6. List users with filter
        try:
            result = client.list_users(page=1, page_size=10, filter_str="john")
            pretty_print("6. LIST USERS (filter: 'john')", result)
        except grpc.RpcError as e:
            print(f"List users filtered failed: {e}")

        # 7. Update user
        try:
            result = client.update_user(
                user_id="user-002",
                email="john.updated@example.com",
                full_name="John Updated Doe",
                metadata={"role": "senior_user", "team": "backend"}
            )
            pretty_print("7. UPDATE USER (user-002)", result)
        except grpc.RpcError as e:
            print(f"Update user failed: {e}")

        # 8. Get updated user
        try:
            result = client.get_user("user-002")
            pretty_print("8. GET UPDATED USER (user-002)", result)
        except grpc.RpcError as e:
            print(f"Get updated user failed: {e}")

        # 9. Login failure test
        try:
            result = client.login("admin", "wrongpassword")
            pretty_print("9. LOGIN FAILURE TEST", result)
        except grpc.RpcError as e:
            pretty_print("9. LOGIN FAILURE TEST (RPC Error)", {
                "code": str(e.code()),
                "details": e.details()
            })

        # 10. Get non-existent user
        try:
            result = client.get_user("nonexistent-user")
            pretty_print("10. GET NON-EXISTENT USER", result)
        except grpc.RpcError as e:
            pretty_print("10. GET NON-EXISTENT USER (RPC Error)", {
                "code": str(e.code()),
                "details": e.details()
            })

        # 11. Logout
        try:
            result = client.logout(token)
            pretty_print("11. LOGOUT", result)
        except grpc.RpcError as e:
            print(f"Logout failed: {e}")

        # 12. Validate invalidated token
        try:
            result = client.validate_token(token)
            pretty_print("12. VALIDATE INVALIDATED TOKEN", result)
        except grpc.RpcError as e:
            print(f"Validate invalidated token failed: {e}")

        print("\n" + "#" * 60)
        print("  DEMO COMPLETE")
        print("#" * 60)


def run_demo_without_grpc():
    """Run a demo using the in-memory database directly (no gRPC needed)."""
    import json

    def pretty_print(label, data):
        print(f"\n{'=' * 50}")
        print(f"  {label}")
        print(f"{'=' * 50}")
        if isinstance(data, dict):
            print(json.dumps(data, indent=2, default=str))
        else:
            print(data)

    print("\n" + "#" * 60)
    print("  MICROSERVICES DEMO (Direct Database - No gRPC)")
    print("#" * 60)

    # 1. Register
    user_id = db.register_user("demo_user", "demo@example.com", "demo123", "Demo User")
    pretty_print("1. REGISTER", {"user_id": user_id, "success": bool(user_id)})

    # 2. Authenticate
    user = db.authenticate("admin", "admin123")
    pretty_print("2. LOGIN", {
        "success": bool(user),
        "user": {k: v for k, v in user.items() if k != "password_hash"} if user else None
    })

    # 3. Create token
    if user:
        token = db.create_token(user["user_id"])
        pretty_print("3. CREATE TOKEN", {"token": token})

        # 4. Validate token
        validated = db.validate_token(token)
        pretty_print("4. VALIDATE TOKEN", {
            "valid": bool(validated),
            "username": validated["username"] if validated else None
        })

    # 5. List users
    users, total = db.list_users(1, 10)
    pretty_print("5. LIST USERS", {
        "total": total,
        "users": [{k: v for k, v in u.items() if k != "password_hash"} for u in users]
    })

    # 6. Update user
    updated = db.update_user("user-002", email="updated@example.com",
                             metadata={"updated": "true"})
    pretty_print("6. UPDATE USER", {
        "success": bool(updated),
        "user": {k: v for k, v in updated.items() if k != "password_hash"} if updated else None
    })

    # 7. Get user
    user = db.get_user("user-002")
    pretty_print("7. GET USER", {
        "user": {k: v for k, v in user.items() if k != "password_hash"} if user else None
    })

    # 8. Logout
    if 'token' in dir():
        success = db.invalidate_token(token)
        pretty_print("8. LOGOUT", {"success": success})

    print("\n" + "#" * 60)
    print("  DEMO COMPLETE")
    print("#" * 60)


