if __name__ == "__main__":
    import argparse

    parser = argparse.ArgumentParser(description="Microservices gRPC Server/Client")
    parser.add_argument(
        "mode",
        choices=["server", "client", "demo", "compile"],
        nargs="?",
        default="demo",
        help="Run mode: 'server' to start gRPC server, 'client' to run client demo, "
             "'demo' for direct database demo, 'compile' to compile proto files"
    )
    parser.add_argument("--host", default="localhost", help="Server host (default: localhost)")
    parser.add_argument("--port", type=int, default=50051, help="Server port (default: 50051)")
    parser.add_argument("--workers", type=int, default=10, help="Max worker threads (default: 10)")

    args = parser.parse_args()

    if args.mode == "compile":
        compile_proto()
    elif args.mode == "server":
        if not GRPC_AVAILABLE:
            print("grpcio is required. Install with: pip install grpcio grpcio-tools")
            sys.exit(1)
        server = MicroservicesServer(
            host=args.host, port=args.port, max_workers=args.workers
        )
        server.start()
        try:
            server.wait_for_termination()
        except KeyboardInterrupt:
            server.stop()
    elif args.mode == "client":
        if not GRPC_AVAILABLE:
            print("grpcio is required. Install with: pip install grpcio grpcio-tools")
            sys.exit(1)
        run_client_demo()
    elif args.mode == "demo":
        run_demo_without_grpc()